-- Glamping.com North America directory audit (May 2026).
-- Adds 52 properties missing from all_glamping_properties vs glamping.com sitemap (135 NA listings).
-- Reclassifies existing Glamping.com-listed rows where is_glamping_property = 'No'.
-- discovery_source = glamping_com_north_america_2026_05. Safe to re-run (WHERE NOT EXISTS guards).

-- Reclassify existing North America Glamping.com listings flagged as non-glamping.
UPDATE public.all_glamping_properties
SET
  is_glamping_property = 'Yes',
  research_status = CASE WHEN research_status = 'rejected' THEN 'published' ELSE research_status END,
  property_type = COALESCE(NULLIF(trim(property_type), ''), 'Glamping Resort'),
  date_updated = '2026-05-26',
  notes = COALESCE(notes, '') || E'\n\nGlamping.com North America directory audit (May 2026): confirmed glamping inventory.'
WHERE property_name IN (
  'Verde Ranch Resort',
  'American Safari Camp',
  'Gateway Canyons Resort & Spa',
  'Headwaters Jupiter',
  'Norwegian Wood Ranch',
  'The Eagle''s Nest',
  'Moonbeam Bungalows',
  'Shawnee Inn & Golf Resort',
  'Flying Flags RV Resort & Campground'
)
  AND is_glamping_property <> 'Yes';

