) AS v(
  research_status, is_glamping_property, is_open, property_name, slug, property_type, unit_type,
  source, discovery_source, country, state, city, lat, lon, url, description, notes,
  date_added, date_updated, land_operator_category, gc_url
)
WHERE NOT EXISTS (
  SELECT 1 FROM public.all_glamping_properties p
  WHERE lower(trim(p.property_name)) = lower(trim(v.property_name))
     OR lower(trim(p.slug)) = lower(trim(v.slug))
     OR lower(trim(COALESCE(p.url, ''))) = lower(trim(v.url))
     OR lower(trim(COALESCE(p.url, ''))) = lower(trim(v.gc_url))
     OR COALESCE(p.notes, '') ILIKE '%' || replace(v.gc_url, 'https://www.glamping.com', '') || '%'
);
